    // Given N=1000, a simple array sort might pass, but let's simulate a min-heap structure conceptually.
    // Since we are in TypeScript environment constraints, a simple array search/pop simulating a PQ is often used in contest settings if a proper PriorityQueue class is unavailable.

    const pq: [number, number][] = [[0, startNode]]; // [distance, node]

    while (pq.length > 0) {
        // Simulate min-heap extraction: find the minimum distance node
        pq.sort((a, b) => a[0] - b[0]);
        const [d, u] = pq.shift()!;

        if (d > distances[u]) continue;

        const neighbors = adj.get(u) || [];

        for (const [v, weight] of neighbors) {
            const newDist = distances[u] + weight;
            if (newDist < distances[v]) {
                distances[v] = newDist;
                pq.push([newDist, v]);
            }
        }
    }
    return distances;
}


function solve(n: number, prices: number[], roads: number[][]): number[] {
    // 1. Build adjacency lists for G_empty and G_full

    // G_empty: weight = cost_i
    const adjEmpty = new Map<number, [number, number][]>();
    // G_full: weight = cost_i * tax_i
    const adjFull = new Map<number, [number, number][]>();

    for (const [u, v, cost, tax] of roads) {
        // Road is bidirectional

        // G_empty
        if (!adjEmpty.has(u)) adjEmpty.set(u, []);
        adjEmpty.get(u)!.push([v, cost]);
        if (!adjEmpty.has(v)) adjEmpty.set(v, []);
        adjEmpty.get(v)!.push([u, cost]);

        // G_full
        const fullCost = cost * tax;
        if (!adjFull.has(u)) adjFull.set(u, []);
        adjFull.get(u)!.push([v, fullCost]);
        if (!adjFull.has(v)) adjFull.set(v, []);
        adjFull.get(v)!.push([u, fullCost]);
    }

    // 2. Compute All-Pairs Shortest Path (APSP)

    // D_empty[i][j]: Shortest path i -> j using cost
    const D_empty: number[][] = [];
    for (let i = 0; i < n; i++) {
        D_empty.push(dijkstra(n, adjEmpty, i));
    }

    // D_full[i][j]: Shortest path i -> j using cost * tax
    const D_full: number[][] = [];
    for (let i = 0; i < n; i++) {
        D_full.push(dijkstra(n, adjFull, i));
    }

    // 3. Calculate the minimum cost for each store i
    const ans: number[] = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Travel to j, buy at j, return to i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Cost to go empty-handed i -> j: D_empty[i][j]
            const cost_i_to_j_empty = D_empty[i][j];

            // Cost to return carrying apples j -> i: D_full[j][i]
            const cost_j_to_i_full = D_full[j][i];

            // Check if paths exist (distances should not be Infinity)
            if (cost_i_to_j_empty !== Number.MAX_SAFE_INTEGER && cost_j_to_i_full !== Number.MAX_SAFE_INTEGER) {
                // Total cost = Travel_Empty + Travel_Full + Price[j]
                const totalCost = cost_i_to_j_empty + cost_j_to_i_full + prices[j];

                if (totalCost < minCost) {
                    minCost = totalCost;
                }
            }
        }
        ans[i] = minCost;
    }

    return ans;
}
